// ============================================================
// URL Param Utilities
// ============================================================

function getParam(name) {
  return new URLSearchParams(window.location.search).get(name);
}

// ============================================================
// Render Utilities
// ============================================================

function escHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function priorityMeta(priority) {
  const map = {
    urgent:    { label: '緊急', class: 'priority-urgent' },
    important: { label: '重要', class: 'priority-important' },
    normal:    { label: '通常', class: 'priority-normal' },
  };
  return map[priority] || map.normal;
}

function brandLabel(brand) {
  if (brand === 'all') return '全店共通';
  const b = BRANDS.find(x => x.id === brand);
  return b ? b.name : brand;
}

function formatDate(dateStr) {
  const d = new Date(dateStr);
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日`;
}

function buildNavbar({ backHref, backLabel, breadcrumbs, title }) {
  const crumbs = (breadcrumbs || [])
    .map(c => `<span class="nav-breadcrumb-item">${escHtml(c)}</span>`)
    .join('<span class="sep"> › </span>');

  return `
    <nav class="navbar">
      ${backHref ? `
      <a href="${escHtml(backHref)}" class="nav-back">
        <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5">
          <path d="M10 12l-4-4 4-4"/>
        </svg>
        ${escHtml(backLabel)}
      </a>` : ''}
      <div class="nav-breadcrumb">${crumbs}</div>
      ${title ? `<span class="navbar-title">${escHtml(title)}</span>` : ''}
    </nav>
  `;
}

// ============================================================
// Exported helpers
// ============================================================

window.AppData = { BRANDS, NOTICES };
window.AppUtils = { getParam, escHtml, priorityMeta, brandLabel, formatDate, buildNavbar };
